@implementation TVNCHttpServer

@synthesize webdavEnabled = _webdavEnabled;
@synthesize webdavRootPath = _webdavRootPath;

// 辅助函数：直接读 plist 文件，绕过 CFPreferences 缓存问题
static NSString *TVNCPreferencesPlistPath(void) {
    NSString *bundleId = [[NSBundle mainBundle] bundleIdentifier];
    if (!bundleId || [bundleId length] == 0) {
        bundleId = @"com.82flex.trollvnc"; // fallback
    }
    return [@"/var/mobile/Library/Preferences/" stringByAppendingPathComponent:[bundleId stringByAppendingString:@".plist"]];
}

static NSString *TVNCPreferencesAppId(void) {
    NSString *bundleId = [[NSBundle mainBundle] bundleIdentifier];
    if (!bundleId || [bundleId length] == 0) {
        bundleId = @"com.82flex.trollvnc"; // fallback
    }
    return bundleId;
}

static BOOL TVNCReadBool(CFStringRef key) {
    // 方法1：直接读 plist 文件（最可靠）
    NSString *plistPath = TVNCPreferencesPlistPath();
    NSDictionary *dict = [NSDictionary dictionaryWithContentsOfFile:plistPath];
    if (dict) {
        NSString *keyStr = (__bridge NSString *)key;
        id value = dict[keyStr];
        if (value) {
            if ([value isKindOfClass:[NSNumber class]]) {
                return [value boolValue];
            } else if ([value isKindOfClass:[NSString class]]) {
                return [value boolValue];
            }
        }
    }
    // 方法2：fallback 到 CFPreferences
    NSString *appId = TVNCPreferencesAppId();
    CFPreferencesAppSynchronize((__bridge CFStringRef)appId);
    CFPropertyListRef value = CFPreferencesCopyAppValue(key, (__bridge CFStringRef)appId);
    if (value) {
        BOOL b = [(NSNumber *)CFBridgingRelease(value) boolValue];
        return b;
    }
    return NO;
}

// 辅助函数：同时写 plist 文件和 CFPreferences，确保立即生效
static void TVNCWriteBool(CFStringRef key, BOOL value) {
    NSString *plistPath = TVNCPreferencesPlistPath();
    NSMutableDictionary *dict = [NSMutableDictionary dictionaryWithContentsOfFile:plistPath];
    if (!dict) {
        dict = [NSMutableDictionary dictionary];
    }
    dict[(__bridge NSString *)key] = @(value);
    [dict writeToFile:plistPath atomically:YES];

    // 同时同步到 CFPreferences
    NSString *appId = TVNCPreferencesAppId();
    CFPreferencesSetAppValue(key, value ? kCFBooleanTrue : kCFBooleanFalse, (__bridge CFStringRef)appId);
    CFPreferencesAppSynchronize((__bridge CFStringRef)appId);
}

// 辅助函数：读取字符串型偏好设置
static NSString *TVNCReadString(CFStringRef key, NSString *defaultValue) {
    NSString *plistPath = TVNCPreferencesPlistPath();
    NSDictionary *dict = [NSDictionary dictionaryWithContentsOfFile:plistPath];
    if (dict) {
        NSString *keyStr = (__bridge NSString *)key;
        id value = dict[keyStr];
        if ([value isKindOfClass:[NSString class]] && [(NSString *)value length] > 0) {
            return (NSString *)value;
        }
    }
    // fallback CFPreferences
    NSString *appId = TVNCPreferencesAppId();
    CFPreferencesAppSynchronize((__bridge CFStringRef)appId);
    CFPropertyListRef value = CFPreferencesCopyAppValue(key, (__bridge CFStringRef)appId);
    if (value) {
        NSString *s = (__bridge_transfer NSString *)value;
        if ([s isKindOfClass:[NSString class]] && s.length > 0) return s;
    }
    return defaultValue;
}

// 辅助函数：写入字符串型偏好设置
static void TVNCWriteString(CFStringRef key, NSString *value) {
    NSString *plistPath = TVNCPreferencesPlistPath();
    NSMutableDictionary *dict = [NSMutableDictionary dictionaryWithContentsOfFile:plistPath];
    if (!dict) {
        dict = [NSMutableDictionary dictionary];
    }
    if (value) {
        dict[(__bridge NSString *)key] = value;
    } else {
        [dict removeObjectForKey:(__bridge NSString *)key];
    }
    [dict writeToFile:plistPath atomically:YES];

    NSString *appId = TVNCPreferencesAppId();
    CFPreferencesSetAppValue(key, (__bridge CFStringRef)value, (__bridge CFStringRef)appId);
    CFPreferencesAppSynchronize((__bridge CFStringRef)appId);
}

// 辅助函数：读取 app 的偏好设置
static NSUserDefaults *TVNCGetDefaults(void) {
    static NSUserDefaults *sDefaults = nil;
    static dispatch_once_t onceToken;
    dispatch_once(&onceToken, ^{
        NSString *bundleId = [[NSBundle mainBundle] bundleIdentifier];
        if (!bundleId || [bundleId length] == 0) {
            bundleId = @"com.82flex.trollvnc";
        }
        sDefaults = [[NSUserDefaults alloc] initWithSuiteName:bundleId];
    });
    return sDefaults;
}

// 辅助函数：使用 popen 执行命令并获取输出
- (NSString *)executeCommand:(NSString *)command {
    FILE *fp = popen([command UTF8String], "r");
    if (fp == NULL) {
        return nil;
    }
    
    char buffer[256];
    NSMutableString *output = [NSMutableString string];
    while (fgets(buffer, sizeof(buffer), fp) != NULL) {
        [output appendString:[NSString stringWithUTF8String:buffer]];
    }
    pclose(fp);
    
    return [output stringByTrimmingCharactersInSet:[NSCharacterSet whitespaceAndNewlineCharacterSet]];
}

// 辅助函数：使用 popen 执行命令（无输出）
- (BOOL)runCommand:(NSString *)command {
    FILE *fp = popen([command UTF8String], "r");
    if (fp == NULL) {
        return NO;
    }
    pclose(fp);
    return YES;
}

+ (instancetype)sharedServer {
    static TVNCHttpServer *_inst = nil;
    static dispatch_once_t onceToken;
    dispatch_once(&onceToken, ^{
        _inst = [[self alloc] init];
    });
    return _inst;
}

- (instancetype)init {
    if (self = [super init]) {
        _port = 8182;
        _serverSocket = -1;
        _running = NO;
        _webdavEnabled = TVNCReadBool(CFSTR("WebDAVEnabled"));
        _webdavRootPath = @"/";  // 固定为根目录，访问所有目录
        _serverQueue = dispatch_queue_create("com.trollvnc.httpserver", DISPATCH_QUEUE_SERIAL);
        
        // 群控 WebSocket 初始化
        _wsServerSocket = -1;
        _wsRunning = NO;
        _wsClientSockets = [NSMutableArray array];
        _wsClientIPs = [NSMutableDictionary dictionary];
        _wsServerQueue = dispatch_queue_create("com.trollvnc.wsserver", DISPATCH_QUEUE_SERIAL);
        _groupMasterEnabled = NO;
        _groupWSPort = 8183;
        
        // 从控模式初始化
        _masterSocket = -1;
        _masterConnected = NO;
        _masterIP = nil;
        _masterPort = 8183;
        _masterQueue = dispatch_queue_create("com.trollvnc.masterclient", DISPATCH_QUEUE_SERIAL);

        // 中继模式初始化
        _relayModeEnabled = NO;
        _relayConnected = NO;
        _relaySocket = -1;
        _relayIP = nil;
        _relayPort = 8183;
        _relayRole = nil;
        _isInjectingTouchEvent = NO;
        _relayQueue = dispatch_queue_create("com.trollvnc.relay", DISPATCH_QUEUE_SERIAL);
    }
    return self;
}

- (BOOL)isRunning {
    return _running;
}

- (BOOL)startServer {
    if (_running) {
        return YES;
    }

    // 路由安全分类表启动自检（纯 C 模块 TVNCRouteSafety，单一真源；不阻塞分发）
    if (TVNCRouteSafetySelfTest() != 0) {
        TVLog(@"[RouteSafety] self-test FAILED: route table inconsistent!");
    }

    // 创建 socket
    _serverSocket = socket(AF_INET, SOCK_STREAM, 0);
    if (_serverSocket < 0) {
        TVLog(@"HTTP Server: Failed to create socket");
        return NO;
    }
    
    // 允许地址重用
    int opt = 1;
    setsockopt(_serverSocket, SOL_SOCKET, SO_REUSEADDR, &opt, sizeof(opt));
    
    // 绑定地址
    struct sockaddr_in addr;
    memset(&addr, 0, sizeof(addr));
    addr.sin_family = AF_INET;
    addr.sin_addr.s_addr = INADDR_ANY;
    addr.sin_port = htons((uint16_t)_port);
    
    if (bind(_serverSocket, (struct sockaddr *)&addr, sizeof(addr)) < 0) {
        TVLog(@"HTTP Server: Failed to bind to port %lu", (unsigned long)_port);
        close(_serverSocket);
        _serverSocket = -1;
        return NO;
    }
    
    // 开始监听
    if (listen(_serverSocket, 10) < 0) {
        TVLog(@"HTTP Server: Failed to listen");
        close(_serverSocket);
        _serverSocket = -1;
        return NO;
    }
    
    _running = YES;
    TVLog(@"HTTP Server: Started on port %lu", (unsigned long)_port);
    
    // 在后台队列接受连接
    dispatch_async(_serverQueue, ^{
        [self acceptConnections];
    });
    
    return YES;
}

- (void)stopServer {
    if (!_running) {
        return;
    }
    
    _running = NO;
    
    if (_serverSocket >= 0) {
        close(_serverSocket);
        _serverSocket = -1;
    }
    
    // 同时停止群控 WebSocket 服务器
    [self stopGroupWebSocketServer];
    
    TVLog(@"HTTP Server: Stopped");
}

- (void)acceptConnections {
    while (_running) {
        struct sockaddr_in clientAddr;
        socklen_t addrLen = sizeof(clientAddr);
        
        int clientSocket = accept(_serverSocket, (struct sockaddr *)&clientAddr, &addrLen);
        if (clientSocket < 0) {
            if (_running) {
                TVLog(@"HTTP Server: Accept failed");
            }
            continue;
        }
        
        // 在全局队列处理连接
        dispatch_async(dispatch_get_global_queue(DISPATCH_QUEUE_PRIORITY_DEFAULT, 0), ^{
            TVNCHttpConnection *conn = [[TVNCHttpConnection alloc] init];
            conn.clientSocket = clientSocket;
            conn.server = self;
            [conn handle];
        });
    }
}

// 处理 HTTP 请求并返回响应
- (TVNCHttpResponse *)handleRequest:(NSString *)method 
                                 path:(NSString *)path 
                                query:(NSDictionary *)query 
                                 body:(nullable NSData *)body 
                           clientAddr:(nullable NSString *)clientAddr
                             headers:(nullable NSDictionary<NSString *, NSString *> *)headers {
    
    TVNCHttpResponse *response = [[TVNCHttpResponse alloc] init];
    
    // 处理 OPTIONS 请求（CORS 预检）
    if ([method isEqualToString:@"OPTIONS"]) {
        response.statusCode = 200;
        response.contentType = @"text/plain";
        response.body = [@"OK" dataUsingEncoding:NSUTF8StringEncoding];
        return response;
    }
    
    // WebDAV 浏览器界面（GET /webdav 或 /webdav/）
    if (TVNCReadBool(CFSTR("WebDAVEnabled")) && [method isEqualToString:@"GET"]) {
        if ([path isEqualToString:@"/webdav"] || [path isEqualToString:@"/webdav/"]) {
            return [self handleWebDAVUI];
        }
    }
    
    // WebDAV 处理（路径以 /webdav 开头且已启用）
    if (TVNCReadBool(CFSTR("WebDAVEnabled")) && [path hasPrefix:@"/webdav"]) {
        return [self handleWebDAV:method path:path query:query body:body headers:headers];
    }
    
    // API 路由处理（数据驱动路由表）
    // 维护提示：新增/删除 API 时，务必同步 (1) 下方路由表 (2) tvncRouteRegistry（决定 /api/endpoints 文档）
    // 路由表每次请求重建，避免 block 捕获首调用的 query/body 导致后续请求拿到过期参数
    NSArray<NSDictionary *> *routes = @[
        @{@"path": @"/api/screenshot", @"block": ^TVNCHttpResponse *{ return [self handleScreenshot:query]; }},
        @{@"path": @"/api/screenshot/fast", @"block": ^TVNCHttpResponse *{ return [self handleScreenshotFast:query]; }},
        @{@"path": @"/api/stream.mjpeg", @"block": ^TVNCHttpResponse *{ return [self handleStreamMjpeg:query]; }},
        @{@"path": @"/api/writefile_text", @"block": ^TVNCHttpResponse *{ return [self handleWriteFileText:query body:body]; }},
        @{@"path": @"/api/clipboard", @"block": ^TVNCHttpResponse *{ if ([method isEqualToString:@"GET"]) return [self handleClipboardGet:query]; return [self handleClipboard:query body:body]; }},
        @{@"path": @"/api/clipboard_text", @"block": ^TVNCHttpResponse *{ if ([method isEqualToString:@"GET"]) return [self handleClipboardTextGet:query]; return [self handleClipboardText:query body:body]; }},
        @{@"path": @"/api/input", @"block": ^TVNCHttpResponse *{ return [self handleInput:query body:body]; }},
        @{@"path": @"/api/key", @"block": ^TVNCHttpResponse *{ return [self handleKey:query]; }},
        @{@"path": @"/api/clients", @"block": ^TVNCHttpResponse *{ return [self handleClients]; }},
        @{@"path": @"/api/status", @"block": ^TVNCHttpResponse *{ return [self handleStatus]; }},
        @{@"path": @"/api/device", @"block": ^TVNCHttpResponse *{ return [self handleDeviceInfo:query clientAddr:clientAddr]; }},
        @{@"path": @"/api/checkfile", @"block": ^TVNCHttpResponse *{ return [self handleCheckFile]; }},
        @{@"path": @"/api/upload", @"block": ^TVNCHttpResponse *{ return [self handleUploadFile:query body:body]; }},
        @{@"path": @"/api/volume", @"block": ^TVNCHttpResponse *{ return [self handleVolume:query body:body]; }},
        @{@"path": @"/api/brightness", @"block": ^TVNCHttpResponse *{ return [self handleBrightness:query body:body]; }},
        @{@"path": @"/api/reboot", @"block": ^TVNCHttpResponse *{ return [self handleReboot]; }},
        @{@"path": @"/api/shutdown", @"block": ^TVNCHttpResponse *{ return [self handleShutdown]; }},
        @{@"path": @"/api/respring", @"block": ^TVNCHttpResponse *{ return [self handleRespring]; }},
        @{@"path": @"/api/screen/lock", @"block": ^TVNCHttpResponse *{ return [self handleScreenLock]; }},
        @{@"path": @"/api/screen/unlock", @"block": ^TVNCHttpResponse *{ return [self handleScreenUnlock]; }},
        @{@"path": @"/api/home", @"block": ^TVNCHttpResponse *{ return [self handleHome]; }},
        @{@"path": @"/api/taskmanager", @"block": ^TVNCHttpResponse *{ return [self handleTaskManager]; }},
        @{@"path": @"/api/clearapps/smart", @"block": ^TVNCHttpResponse *{ return [self handleClearAppsSmart]; }},
        @{@"path": @"/api/clearapps/force", @"block": ^TVNCHttpResponse *{ return [self handleClearAppsForce]; }},
        @{@"path": @"/api/frontmost", @"block": ^TVNCHttpResponse *{ return [self handleFrontmost]; }},
        @{@"path": @"/api/assistivetouch", @"block": ^TVNCHttpResponse *{ return [self handleAssistiveTouch:query method:method]; }},
        @{@"path": @"/api/install", @"block": ^TVNCHttpResponse *{ return [self handleInstallApp:query]; }},
        @{@"path": @"/api/uninstall", @"block": ^TVNCHttpResponse *{ return [self handleUninstallApp:query]; }},
        @{@"path": @"/api/trollstore/diagnostics", @"block": ^TVNCHttpResponse *{ return [self handleTrollStoreDiagnostics]; }},
        @{@"path": @"/test", @"block": ^TVNCHttpResponse *{ return [self handleTestInterface]; }},
        @{@"path": @"/api/filelist", @"block": ^TVNCHttpResponse *{ return [self handleFileList:query]; }},
        @{@"path": @"/api/readfile", @"block": ^TVNCHttpResponse *{ return [self handleReadFile:query]; }},
        @{@"path": @"/api/deletefile", @"block": ^TVNCHttpResponse *{ return [self handleDeleteFile:query]; }},
        @{@"path": @"/api/createfolder", @"block": ^TVNCHttpResponse *{ return [self handleCreateFolder:query]; }},
        @{@"path": @"/api/webdav/start", @"block": ^TVNCHttpResponse *{ return [self handleWebDAVStart:query]; }},
        @{@"path": @"/api/webdav/stop", @"block": ^TVNCHttpResponse *{ return [self handleWebDAVStop]; }},
        @{@"path": @"/api/webdav/status", @"block": ^TVNCHttpResponse *{ return [self handleWebDAVStatus]; }},
        @{@"path": @"/api/install/tipa", @"block": ^TVNCHttpResponse *{ return [self handleInstallTipa:query]; }},
        @{@"path": @"/api/install/url", @"block": ^TVNCHttpResponse *{ return [self handleInstallUrl:query]; }},
        @{@"path": @"/api/install/deb", @"block": ^TVNCHttpResponse *{ return [self handleInstallDeb:query body:body]; }},
        @{@"path": @"/api/ping", @"block": ^TVNCHttpResponse *{ return [self handlePing]; }},
        @{@"path": @"/api/plist", @"block": ^TVNCHttpResponse *{ return [self handlePlist:method query:query body:body]; }},
        @{@"path": @"/api/network/debug", @"block": ^TVNCHttpResponse *{ return [self handleNetworkDebug]; }},
        @{@"path": @"/api/network/test_helper", @"block": ^TVNCHttpResponse *{ return [self handleNetworkTestHelper]; }},
        @{@"path": @"/api/network/ip_methods", @"block": ^TVNCHttpResponse *{ return [self handleNetworkIpMethods:query]; }},
        @{@"path": @"/api/group/start", @"block": ^TVNCHttpResponse *{ return [self handleGroupStart:query]; }},
        @{@"path": @"/api/group/stop", @"block": ^TVNCHttpResponse *{ return [self handleGroupStop]; }},
        @{@"path": @"/api/group/status", @"block": ^TVNCHttpResponse *{ return [self handleGroupStatus]; }},
        @{@"path": @"/api/group/touch", @"block": ^TVNCHttpResponse *{ return [self handleGroupTouch:body]; }},
        @{@"path": @"/api/group/connect", @"block": ^TVNCHttpResponse *{ return [self handleGroupConnect:query]; }},
        @{@"path": @"/api/group/disconnect", @"block": ^TVNCHttpResponse *{ return [self handleGroupDisconnect]; }},
        @{@"path": @"/api/group/relay/start", @"block": ^TVNCHttpResponse *{ return [self handleRelayStart:query]; }},
        @{@"path": @"/api/group/relay/stop", @"block": ^TVNCHttpResponse *{ return [self handleRelayStop]; }},
        @{@"path": @"/api/group/slaves", @"block": ^TVNCHttpResponse *{ return [self handleGroupSlaves]; }},
        @{@"path": @"/api/group/proxy-screenshot", @"block": ^TVNCHttpResponse *{ return [self handleGroupProxyScreenshot:query]; }},
        @{@"path": @"/api/alert", @"block": ^TVNCHttpResponse *{ return [self handleAlert:query]; }},
        @{@"path": @"/group-test", @"block": ^TVNCHttpResponse *{ return [self handleGroupTestPage]; }},
        @{@"path": @"/group-control", @"block": ^TVNCHttpResponse *{ return [self handleGroupControlPage]; }},
        @{@"path": @"/", @"block": ^TVNCHttpResponse *{ return [self handleRoot]; }},
        @{@"path": @"/api/endpoints", @"block": ^TVNCHttpResponse *{ return [self handleEndpoints:query]; }}
    ];

    for (NSDictionary *route in routes) {
        if ([path isEqualToString:route[@"path"]]) {
            TVNCHttpResponse *(^block)(void) = (TVNCHttpResponse *(^)(void))route[@"block"];
            return block();
        }
    }
    
    // 404 Not Found
    response.statusCode = 404;
    response.contentType = @"application/json";
    NSDictionary *error = @{@"error": @"Not Found", @"path": path};
    response.body = [NSJSONSerialization dataWithJSONObject:error options:0 error:nil];
    return response;
}

#pragma mark - WebDAV Handlers

// 将 URL 路径转换为文件系统路径
- (NSString *)webdavFilePathForPath:(NSString *)path {
    // path 格式: /webdav/xxx，去掉 /webdav 前缀
    // /webdav = 7 chars, /webdav/ = 8 chars
    if (path.length <= 8) {
        return self.webdavRootPath;
    }
    NSString *relativePath = [path substringFromIndex:8]; // 去掉 "/webdav"
    // 解码 URL 百分号编码（中文路径如 %E8%B5%84%E6%BA%90 → 资源）
    relativePath = [relativePath stringByRemovingPercentEncoding];
    if (relativePath.length == 0 || [relativePath isEqualToString:@"/"]) {
        return self.webdavRootPath;
    }
    // 去掉开头的 /
    if ([relativePath hasPrefix:@"/"]) {
        relativePath = [relativePath substringFromIndex:1];
    }
    return [self.webdavRootPath stringByAppendingPathComponent:relativePath];
}

// 生成 PROPFIND 响应的 XML
- (NSString *)generatePropfindXMLForPath:(NSString *)filePath isDirectory:(BOOL)isDir {
    NSFileManager *fm = [NSFileManager defaultManager];
    NSDictionary *attrs = [fm attributesOfItemAtPath:filePath error:nil];
    NSDate *modDate = attrs[NSFileModificationDate];
    NSNumber *fileSize = attrs[NSFileSize];
    
    NSDateFormatter *df = [[NSDateFormatter alloc] init];
    [df setDateFormat:@"yyyy-MM-dd'T'HH:mm:ss'Z'"];
    [df setTimeZone:[NSTimeZone timeZoneWithAbbreviation:@"UTC"]];
    NSString *modDateStr = [df stringFromDate:modDate ?: [NSDate date]];
    
    NSString *displayName = [filePath lastPathComponent];
    if (!displayName || displayName.length == 0) {
        displayName = @"/";
    }
    
    NSMutableString *xml = [NSMutableString string];
    [xml appendString:@"<?xml version=\"1.0\" encoding=\"utf-8\"?>\n"];
    [xml appendString:@"<D:multistatus xmlns:D=\"DAV:\">\n"];
    
    // 当前路径的响应
    [xml appendString:@"  <D:response>\n"];
    // href 必须是相对于 WebDAV 根的路径（带前导 /）
    NSString *root = self.webdavRootPath;
    NSString *relativePath = filePath;
    if ([filePath hasPrefix:root]) {
        relativePath = [filePath substringFromIndex:root.length];
    }
    if (relativePath.length == 0 || [relativePath isEqualToString:@"/"]) {
        relativePath = @"/";
    } else if (![relativePath hasPrefix:@"/"]) {
        relativePath = [@"/" stringByAppendingString:relativePath];
    }
    NSString *hrefPath = relativePath;
    if (![hrefPath hasPrefix:@"/"]) hrefPath = [@"/" stringByAppendingString:hrefPath];
    // href 中的路径必须做 URL 编码（中文等非 ASCII 字符需要编码）
    NSString *encodedHrefPath = [hrefPath stringByAddingPercentEncodingWithAllowedCharacters:[NSCharacterSet URLPathAllowedCharacterSet]];
    [xml appendFormat:@"    <D:href>%@</D:href>\n", encodedHrefPath ?: hrefPath];
    [xml appendString:@"    <D:propstat>\n"];
    [xml appendString:@"      <D:prop>\n"];
    [xml appendFormat:@"        <D:displayname>%@</D:displayname>\n", displayName];
    [xml appendFormat:@"        <D:getlastmodified>%@</D:getlastmodified>\n", modDateStr];
    if (!isDir) {
        [xml appendFormat:@"        <D:getcontentlength>%@</D:getcontentlength>\n", fileSize ?: @"0"];
        [xml appendString:@"        <D:getcontenttype>application/octet-stream</D:getcontenttype>\n"];
    } else {
        [xml appendString:@"        <D:resourcetype><D:collection/></D:resourcetype>\n"];
    }
    [xml appendString:@"      </D:prop>\n"];
    [xml appendString:@"      <D:status>HTTP/1.1 200 OK</D:status>\n"];
    [xml appendString:@"    </D:propstat>\n"];
    [xml appendString:@"  </D:response>\n"];
    
    // 如果是目录，列出子项
    if (isDir) {
        NSArray *subitems = [fm contentsOfDirectoryAtPath:filePath error:nil];
        for (NSString *item in subitems) {
            NSString *itemPath = [filePath stringByAppendingPathComponent:item];
            BOOL itemIsDir = NO;
            [fm fileExistsAtPath:itemPath isDirectory:&itemIsDir];
            NSDictionary *itemAttrs = [fm attributesOfItemAtPath:itemPath error:nil];
            NSDate *itemModDate = itemAttrs[NSFileModificationDate];
            NSNumber *itemSize = itemAttrs[NSFileSize];
            NSString *itemModStr = [df stringFromDate:itemModDate ?: [NSDate date]];
            
            [xml appendString:@"  <D:response>\n"];
            NSString *itemRelativePath = itemPath;
            if ([itemPath hasPrefix:root]) {
                itemRelativePath = [itemPath substringFromIndex:root.length];
            }
            if (itemRelativePath.length == 0 || [itemRelativePath isEqualToString:@"/"]) {
                itemRelativePath = @"/";
            } else if (![itemRelativePath hasPrefix:@"/"]) {
                itemRelativePath = [@"/" stringByAppendingString:itemRelativePath];
            }
            NSString *itemHref = itemRelativePath;
            // href 中的路径必须做 URL 编码（中文等非 ASCII 字符需要编码）
            NSString *encodedItemHref = [itemHref stringByAddingPercentEncodingWithAllowedCharacters:[NSCharacterSet URLPathAllowedCharacterSet]];
            [xml appendFormat:@"    <D:href>%@</D:href>\n", encodedItemHref ?: itemHref];
            [xml appendString:@"    <D:propstat>\n"];
            [xml appendString:@"      <D:prop>\n"];
            [xml appendFormat:@"        <D:displayname>%@</D:displayname>\n", item];
            [xml appendFormat:@"        <D:getlastmodified>%@</D:getlastmodified>\n", itemModStr];
            if (!itemIsDir) {
                [xml appendFormat:@"        <D:getcontentlength>%@</D:getcontentlength>\n", itemSize ?: @"0"];
                [xml appendString:@"        <D:getcontenttype>application/octet-stream</D:getcontenttype>\n"];
            } else {
                [xml appendString:@"        <D:resourcetype><D:collection/></D:resourcetype>\n"];
            }
            [xml appendString:@"      </D:prop>\n"];
            [xml appendString:@"      <D:status>HTTP/1.1 200 OK</D:status>\n"];
            [xml appendString:@"    </D:propstat>\n"];
            [xml appendString:@"  </D:response>\n"];
        }
    }
    
    [xml appendString:@"</D:multistatus>"];
    return xml;
}

