#pragma mark - 电脑中继模式 API

// 从 /var/mobile/Media/fuwuduan.txt 读取电脑 IP
// 支持格式：
//   1. 键值对：serverIP=192.168.1.100
//   2. JSON：{"serverIP": "192.168.1.100"}
//   3. 纯 IP：192.168.1.100
- (NSString *)readServerIPFromConfigFile {
    NSString *configPath = @"/var/mobile/Media/fuwuduan.txt";
    NSFileManager *fm = [NSFileManager defaultManager];
    
    if (![fm fileExistsAtPath:configPath]) {
        TVLog(@"Relay: Config file not found: %@", configPath);
        return nil;
    }
    
    NSError *error = nil;
    NSString *content = [NSString stringWithContentsOfFile:configPath
                                                  encoding:NSUTF8StringEncoding
                                                     error:&error];
    if (!content || content.length == 0) {
        TVLog(@"Relay: Failed to read config file: %@", error.localizedDescription ?: @"empty");
        return nil;
    }
    
    // 去掉首尾空白和换行
    content = [content stringByTrimmingCharactersInSet:[NSCharacterSet whitespaceAndNewlineCharacterSet]];
    
    // 尝试 JSON 格式
    NSData *jsonData = [content dataUsingEncoding:NSUTF8StringEncoding];
    if (jsonData) {
        NSError *jsonError = nil;
        id jsonObject = [NSJSONSerialization JSONObjectWithData:jsonData options:0 error:&jsonError];
        if (jsonObject && [jsonObject isKindOfClass:[NSDictionary class]]) {
            NSString *ip = jsonObject[@"serverIP"];
            if (ip && ip.length > 0) {
                TVLog(@"Relay: Read serverIP from JSON: %@", ip);
                return ip;
            }
        }
    }
    
    // 尝试键值对格式（serverIP=192.168.1.100）
    NSArray *lines = [content componentsSeparatedByString:@"\n"];
    for (NSString *line in lines) {
        NSString *trimmedLine = [line stringByTrimmingCharactersInSet:[NSCharacterSet whitespaceAndNewlineCharacterSet]];
        if ([trimmedLine hasPrefix:@"serverIP="] || [trimmedLine hasPrefix:@"serverIP = "]) {
            NSString *ip = [trimmedLine componentsSeparatedByString:@"="].lastObject;
            ip = [ip stringByTrimmingCharactersInSet:[NSCharacterSet whitespaceAndNewlineCharacterSet]];
            if (ip && ip.length > 0) {
                TVLog(@"Relay: Read serverIP from key-value: %@", ip);
                return ip;
            }
        }
    }
    
    // 尝试纯 IP 格式（整行就是一个 IP 地址）
    // 简单验证：包含数字和点，且至少有 7 个字符（x.x.x.x 最少 7 个字符）
    NSCharacterSet *ipCharSet = [NSCharacterSet characterSetWithCharactersInString:@"0123456789."];
    NSString *filtered = [[content componentsSeparatedByCharactersInSet:[ipCharSet invertedSet]] componentsJoinedByString:@""];
    if (filtered.length >= 7 && [filtered containsString:@"."]) {
        TVLog(@"Relay: Read serverIP as plain IP: %@", filtered);
        return filtered;
    }
    
    TVLog(@"Relay: Cannot parse serverIP from config file");
    return nil;
}

