#pragma mark - TVNCHttpConnection

@implementation TVNCHttpConnection

- (void)handle {
    // 设置接收超时（5分钟，支持大文件上传）
    struct timeval tv;
    tv.tv_sec = 300;
    tv.tv_usec = 0;
    setsockopt(_clientSocket, SOL_SOCKET, SO_RCVTIMEO, &tv, sizeof(tv));
    
    // 预声明变量（避免 goto 跳过初始化）
    NSString *clientAddr = nil;
    struct sockaddr_in peerAddr;
    socklen_t peerLen = sizeof(peerAddr);
    TVNCHttpResponse *response = nil;
    NSData *body = nil;
    
    // 读取请求头
    NSMutableData *headerData = [NSMutableData data];
    uint8_t buffer[8192];
    NSInteger totalReceived = 0;
    NSInteger maxHeaderSize = 64 * 1024; // 最大 64KB 头部
    NSRange headerEndRange = NSMakeRange(NSNotFound, 0);
    
    // 先读取头部（直到 \r\n\r\n）
    while (totalReceived < maxHeaderSize) {
        ssize_t n = recv(_clientSocket, buffer, sizeof(buffer), 0);
        if (n <= 0) break;
        
        [headerData appendBytes:buffer length:n];
        totalReceived += n;
        
        // 查找头部结束标记
        headerEndRange = [headerData rangeOfData:[@"\r\n\r\n" dataUsingEncoding:NSUTF8StringEncoding]
                                         options:0
                                           range:NSMakeRange(0, headerData.length)];
        if (headerEndRange.location != NSNotFound) {
            break;
        }
    }
    
    if (headerEndRange.location == NSNotFound) {
        TVLog(@"HTTP Server: Failed to receive complete headers");
        close(_clientSocket);
        return;
    }
    
    // 解析请求头
    NSUInteger headerLength = headerEndRange.location + headerEndRange.length;
    NSString *headerStr = [[NSString alloc] initWithBytes:headerData.bytes
                                                   length:headerLength
                                                 encoding:NSUTF8StringEncoding];
    NSArray *lines = [headerStr componentsSeparatedByString:@"\r\n"];
    if (lines.count == 0) {
        TVLog(@"HTTP Server: Empty request");
        close(_clientSocket);
        return;
    }
    
    // 解析请求行
    NSArray *requestParts = [lines[0] componentsSeparatedByString:@" "];
    if (requestParts.count < 2) {
        TVLog(@"HTTP Server: Invalid request line: %@", lines[0]);
        close(_clientSocket);
        return;
    }
    
    NSString *method = requestParts[0];
    NSString *fullPath = requestParts[1];
    
    // 解析路径和查询参数
    NSString *path = fullPath;
    NSMutableDictionary *query = [NSMutableDictionary dictionary];
    NSRange queryRange = [fullPath rangeOfString:@"?"];
    if (queryRange.location != NSNotFound) {
        path = [fullPath substringToIndex:queryRange.location];
        NSString *queryString = [fullPath substringFromIndex:queryRange.location + 1];
        NSArray *pairs = [queryString componentsSeparatedByString:@"&"];
        for (NSString *pair in pairs) {
            NSArray *kv = [pair componentsSeparatedByString:@"="];
            if (kv.count == 2) {
                NSString *key = [kv[0] stringByRemovingPercentEncoding];
                NSString *value = [kv[1] stringByRemovingPercentEncoding];
                query[key] = value;
            }
        }
    }
    
    // 解析 Content-Length
    NSInteger contentLength = 0;
    for (NSString *line in lines) {
        if ([line hasPrefix:@"Content-Length: "]) {
            NSString *lenStr = [line substringFromIndex:16];
            contentLength = [lenStr integerValue];
            break;
        }
    }
    
    // 解析所有请求头
    NSMutableDictionary *headers = [NSMutableDictionary dictionary];
    for (NSUInteger i = 1; i < lines.count; i++) {
        NSString *line = lines[i];
        NSRange colonRange = [line rangeOfString:@": "];
        if (colonRange.location != NSNotFound && colonRange.location > 0) {
            NSString *key = [line substringToIndex:colonRange.location];
            NSString *value = [line substringFromIndex:colonRange.location + 2];
            headers[key] = value;
        }
    }
    self.parsedHeaders = headers;
    
    TVLog(@"HTTP Server: %@ %@ (Content-Length: %ld)", method, fullPath, (long)contentLength);
    
    // 处理 body
    NSInteger maxMemorySize = 10 * 1024 * 1024; // 10MB 以下直接读入内存
    
    // 检查是否已有部分 body 数据（在头部之后）
    NSInteger bodyReceived = headerData.length - headerLength;
    NSMutableData *bodyData = [NSMutableData data];
    if (bodyReceived > 0) {
        [bodyData appendBytes:((uint8_t *)headerData.bytes + headerLength) length:bodyReceived];
    }
    
    // 对于大文件上传，使用流式处理（避免全量缓存到内存再写文件）
    BOOL isUploadRequest = [path isEqualToString:@"/api/upload"];
    BOOL isWebDAVPut = ([method isEqualToString:@"PUT"] && [path hasPrefix:@"/webdav"]);
    NSString *tempFilePath = nil;
    int tempFileFd = -1;
    NSString *webdavTargetPath = nil; // WebDAV PUT 直接写入的目标路径（非临时）

    // WebDAV PUT：直接打开目标文件，流式写入
    if (isWebDAVPut && contentLength > maxMemorySize) {
        // 复用 webdavFilePathForPath 的逻辑，计算目标路径
        // 使用 self.server.webdavRootPath 获取正确路径（TVNCHttpConnection 独立于 TVNCHttpServer）
        NSString *rawRelPath = [path substringFromIndex:8];
        NSString *decodedRelPath = [rawRelPath stringByRemovingPercentEncoding] ?: rawRelPath;
        NSString *targetPath = [self.server.webdavRootPath stringByAppendingPathComponent:decodedRelPath];
        // 确保目录存在
        NSString *dirPath = [targetPath stringByDeletingLastPathComponent];
        [[NSFileManager defaultManager] createDirectoryAtPath:dirPath withIntermediateDirectories:YES attributes:nil error:nil];
        // 使用 .tmp 后缀，传输完成后 rename 生效（原子操作）
        webdavTargetPath = [targetPath stringByAppendingString:@".tmp"];
        tempFileFd = open([webdavTargetPath UTF8String], O_WRONLY | O_CREAT | O_TRUNC, 0644);
        if (tempFileFd >= 0 && bodyData.length > 0) {
            write(tempFileFd, bodyData.bytes, bodyData.length);
        }
        NSInteger remaining = contentLength - bodyReceived;
        while (remaining > 0 && tempFileFd >= 0) {
            ssize_t toRead = sizeof(buffer);
            if (toRead > remaining) toRead = remaining;
            ssize_t n = recv(_clientSocket, buffer, toRead, 0);
            if (n <= 0) break;
            write(tempFileFd, buffer, n);
            remaining -= n;
        }
        if (tempFileFd >= 0) {
            close(tempFileFd);
            tempFileFd = -1;
        }
        // 原子 rename：.tmp → 正式路径
        if (webdavTargetPath && [[NSFileManager defaultManager] fileExistsAtPath:webdavTargetPath]) {
            [[NSFileManager defaultManager] removeItemAtPath:targetPath error:nil];
            [[NSFileManager defaultManager] moveItemAtPath:webdavTargetPath toPath:targetPath error:nil];
        }
        // 返回成功响应（跳过下方 handleRequest，直接发送响应）
        TVNCHttpResponse *response = [[TVNCHttpResponse alloc] init];
        response.statusCode = 201;
        response.contentType = @"text/plain";
        response.body = [@"Created" dataUsingEncoding:NSUTF8StringEncoding];
        goto send_response;
    } else if (isUploadRequest && contentLength > maxMemorySize) {
        // 大文件上传：使用临时文件
        tempFilePath = [NSTemporaryDirectory() stringByAppendingPathComponent:[NSString stringWithFormat:@"upload_%ld", (long)time(NULL)]];
        tempFileFd = open([tempFilePath UTF8String], O_WRONLY | O_CREAT | O_TRUNC, 0644);
        
        if (tempFileFd >= 0 && bodyData.length > 0) {
            write(tempFileFd, bodyData.bytes, bodyData.length);
        }
        
        // 继续接收剩余数据到临时文件
        NSInteger remaining = contentLength - bodyReceived;
        while (remaining > 0 && tempFileFd >= 0) {
            ssize_t toRead = sizeof(buffer);
            if (toRead > remaining) toRead = remaining;
            
            ssize_t n = recv(_clientSocket, buffer, toRead, 0);
            if (n <= 0) break;
            
            write(tempFileFd, buffer, n);
            remaining -= n;
        }
        
        if (tempFileFd >= 0) {
            close(tempFileFd);
            // 读取临时文件内容
            body = [NSData dataWithContentsOfFile:tempFilePath];
            // 删除临时文件
            unlink([tempFilePath UTF8String]);
        }
    } else {
        // 小文件或其他请求：读入内存
        // 如果 Content-Length > 0，按长度读取；否则读取直到连接关闭
        if (contentLength > 0) {
            NSInteger remaining = contentLength - bodyReceived;
            while (remaining > 0) {
                ssize_t toRead = sizeof(buffer);
                if (toRead > remaining) toRead = remaining;
                
                ssize_t n = recv(_clientSocket, buffer, toRead, 0);
                if (n <= 0) break;
                
                [bodyData appendBytes:buffer length:n];
                remaining -= n;
            }
        } else if (([method isEqualToString:@"POST"] || [method isEqualToString:@"PUT"]) && bodyReceived > 0) {
            // 有 body 但 Content-Length 为 0，读取直到超时或连接关闭
            // 设置短超时用于检测 body 结束
            struct timeval shortTv;
            shortTv.tv_sec = 1;
            shortTv.tv_usec = 0;
            setsockopt(_clientSocket, SOL_SOCKET, SO_RCVTIMEO, &shortTv, sizeof(shortTv));
            
            while (true) {
                ssize_t n = recv(_clientSocket, buffer, sizeof(buffer), 0);
                if (n <= 0) break;
                [bodyData appendBytes:buffer length:n];
                // 限制最大读取 10MB
                if (bodyData.length > maxMemorySize) break;
            }
            
            // 恢复长超时
            struct timeval longTv;
            longTv.tv_sec = 300;
            longTv.tv_usec = 0;
            setsockopt(_clientSocket, SOL_SOCKET, SO_RCVTIMEO, &longTv, sizeof(longTv));
        }
        
        body = bodyData;
    }
    
    // 获取客户端 IP 地址
    if (getpeername(_clientSocket, (struct sockaddr *)&peerAddr, &peerLen) == 0) {
        char ipStr[INET_ADDRSTRLEN];
        inet_ntop(AF_INET, &peerAddr.sin_addr, ipStr, INET_ADDRSTRLEN);
        clientAddr = [NSString stringWithUTF8String:ipStr];
    }
    
    // 处理请求
    if (!isWebDAVPut || contentLength <= maxMemorySize) {
        response = [_server handleRequest:method path:path query:query body:body clientAddr:clientAddr headers:_parsedHeaders];
    }
    
    // 发送响应
    // MJPEG 流特殊处理：检测 __MJPEG_STREAM__ 标记
    if (response && [response.contentType hasPrefix:@"multipart/x-mixed-replace"] &&
        response.body.length > 17 &&
        [[NSString alloc] initWithBytes:response.body.bytes length:17 encoding:NSUTF8StringEncoding] != nil) {
        NSString *bodyStr = [[NSString alloc] initWithData:response.body encoding:NSUTF8StringEncoding];
        if (bodyStr && [bodyStr hasPrefix:@"__MJPEG_STREAM__"]) {
            // 解析 MJPEG 参数
            NSData *jsonPart = [bodyStr dataUsingEncoding:NSUTF8StringEncoding];
            jsonPart = [jsonPart subdataWithRange:NSMakeRange(17, jsonPart.length - 17)];
            NSDictionary *params = [NSJSONSerialization JSONObjectWithData:jsonPart options:0 error:nil];

            CGFloat mjpegQuality = [params[@"q"] floatValue];
            if (mjpegQuality <= 0) mjpegQuality = 0.6;
            if (mjpegQuality > 1.0) mjpegQuality = 1.0;
            CGFloat mjpegScale = [params[@"scale"] floatValue];
            if (mjpegScale <= 0) mjpegScale = 1.0;
            if (mjpegScale > 1.0) mjpegScale = 1.0;
            int mjpegFps = [params[@"fps"] intValue];
            if (mjpegFps < 1) mjpegFps = 10;
            if (mjpegFps > 30) mjpegFps = 30;
            int mjpegMaxW = [params[@"maxw"] intValue];
            int mjpegMaxH = [params[@"maxh"] intValue];

            // 发送 MJPEG 流头部（不发送 Content-Length，使用 chunked 或持续推送）
            NSString *mjpegHeader = [NSString stringWithFormat:
                @"HTTP/1.1 200 OK\r\n"
                @"Content-Type: multipart/x-mixed-replace; boundary=frameboundary\r\n"
                @"Cache-Control: no-cache, no-store, must-revalidate\r\n"
                @"Pragma: no-cache\r\n"
                @"Connection: close\r\n"
                @"Access-Control-Allow-Origin: *\r\n"
                @"\r\n"];
            send(_clientSocket, mjpegHeader.UTF8String, mjpegHeader.length, 0);

            TVLog(@"[MJPEG] Stream started: q=%.2f scale=%.2f fps=%d maxW=%d maxH=%d",
                  mjpegQuality, mjpegScale, mjpegFps, mjpegMaxW, mjpegMaxH);

            // 持续推送 JPEG 帧
            NSTimeInterval frameInterval = 1.0 / mjpegFps;
            int frameCount = 0;
            BOOL useFramebuffer = [[TVNCApiManager sharedManager] isFramebufferAvailable];

            while (_server.isRunning) {
                @autoreleasepool {
                    // 获取当前帧
                    NSData *jpegData = nil;
                    if (useFramebuffer) {
                        jpegData = [[TVNCApiManager sharedManager]
                            captureScreenshotFromFramebufferWithFormat:@"jpeg"
                                                               quality:mjpegQuality
                                                                 scale:mjpegScale
                                                                  maxW:mjpegMaxW
                                                                  maxH:mjpegMaxH];
                        // 如果帧缓存突然不可用，降级
                        if (!jpegData) {
                            useFramebuffer = [[TVNCApiManager sharedManager] isFramebufferAvailable];
                        }
                    }
                    if (!jpegData) {
                        // 降级到普通截图
                        if (mjpegScale < 1.0) {
                            jpegData = [[TVNCApiManager sharedManager]
                                captureScreenshotWithFormat:@"jpeg"
                                                   quality:mjpegQuality
                                                  rotation:0
                                                     scale:mjpegScale];
                        } else {
                            jpegData = [[TVNCApiManager sharedManager]
                                captureScreenshotAsJPEGWithQuality:mjpegQuality];
                        }
                    }

                    if (jpegData) {
                        // 构建 MJPEG 帧
                        NSString *frameHeader = [NSString stringWithFormat:
                            @"--frameboundary\r\n"
                            @"Content-Type: image/jpeg\r\n"
                            @"Content-Length: %lu\r\n"
                            @"\r\n", (unsigned long)jpegData.length];
                        send(_clientSocket, frameHeader.UTF8String, frameHeader.length, 0);
                        send(_clientSocket, jpegData.bytes, jpegData.length, 0);
                        send(_clientSocket, "\r\n", 2, 0);

                        frameCount++;
                    }

                    // 等待下一帧
                    [NSThread sleepForTimeInterval:frameInterval];

                    // 检查连接是否还活着（非阻塞 recv 检测）
                    char peekBuf[1];
                    ssize_t peekResult = recv(_clientSocket, peekBuf, 1, MSG_PEEK | MSG_DONTWAIT);
                    if (peekResult == 0 || (peekResult < 0 && errno != EAGAIN && errno != EWOULDBLOCK)) {
                        // 客户端断开连接
                        TVLog(@"[MJPEG] Client disconnected after %d frames", frameCount);
                        break;
                    }
                }
            }

            close(_clientSocket);
            return;
        }
    }

    send_response: {
    NSMutableString *responseHeader = [NSMutableString string];
    [responseHeader appendFormat:@"HTTP/1.1 %ld OK\r\n", (long)response.statusCode];
    [responseHeader appendFormat:@"Content-Type: %@\r\n", response.contentType];
    [responseHeader appendFormat:@"Content-Length: %lu\r\n", (unsigned long)response.body.length];
    [responseHeader appendString:@"Access-Control-Allow-Origin: *\r\n"];
    [responseHeader appendString:@"Access-Control-Allow-Methods: GET, POST, OPTIONS, PROPFIND, MKCOL, PUT, DELETE, MOVE, COPY\r\n"];
    [responseHeader appendString:@"Access-Control-Allow-Headers: Content-Type, Content-Length, Accept, Accept-Language, Accept-Encoding, Destination, Overwrite, Depth\r\n"];
    [responseHeader appendString:@"Access-Control-Max-Age: 86400\r\n"];
    [responseHeader appendString:@"DAV: 1, 2\r\n"];
    [responseHeader appendString:@"Connection: close\r\n"];
    [responseHeader appendString:@"\r\n"];
    
    send(_clientSocket, responseHeader.UTF8String, responseHeader.length, 0);
    if (response.body.length > 0) {
        send(_clientSocket, response.body.bytes, response.body.length, 0);
    }
    
    close(_clientSocket);
    } // end send_response block
}

@end
